178	    /**
179	     * 将大纲块结构转换为 Markdown 文本
180	     * 支持所有块类型
181	     */
182	    blocksToMarkdown(blocks: OutlineBlock[]): string {
183	        const lines: string[] = [];
184	
185	        function processBlock(block: OutlineBlock, parentLevel: number = 0) {
186	            switch (block.type) {
187	                case 'heading':
188	                    const hashes = '#'.repeat(block.headingLevel || 1);
189	                    lines.push(`${hashes} ${block.content}`);
190	                    break;
191	
192	                case 'code':
193	                    lines.push('```' + (block.codeLanguage || ''));
194	                    lines.push(block.content);
195	                    lines.push('```');
196	                    break;
197	
198	                case 'quote':
199	                    const quotes = '>'.repeat(block.quoteLevel || 1);
200	                    lines.push(`${quotes} ${block.content}`);
201	                    break;
202	
203	                case 'horizontal':
204	                    lines.push('---');
205	                    break;
206	
207	                case 'paragraph':
208	                    lines.push(block.content);
209	                    break;
210	
211	                case 'blank':
212	                    lines.push('');
213	                    break;
214	
215	                case 'list':
216	                    const indent = '\t'.repeat(block.level);
217	                    let content = block.content;
218	
219	                    // 如果是待办事项，添加复选框标记
220	                    if (block.isTodo) {
221	                        const checkbox = block.todoCompleted ? '[x]' : '[ ]';
222	                        content = `${checkbox} ${content}`;
223	                    }
224	
225	                    // 将内容中的换行符转换为 Markdown 列表项的续行格式
226	                    if (content.includes('\n')) {
227	                        const contentLines = content.split('\n');
228	                        const firstLine = `${indent}- ${contentLines[0]}`;
229	                        const continuationLines = contentLines.slice(1).map(
230	                            line => `${indent}  ${line}`
231	                        );
232	                        lines.push(firstLine);
233	                        lines.push(...continuationLines);
234	                    } else {
235	                        lines.push(`${indent}- ${content}`);
236	                    }
237	
238	                    // 递归处理子块
239	                    for (const child of block.children) {
240	                        processBlock(child, block.level);
241	                    }
242	                    break;
243	            }
244	
245	            // 非列表项的子块（如果有的话）
246	            if (block.type !== 'list') {
247	                for (const child of block.children) {
248	                    processBlock(child, parentLevel);
249	                }
250	            }
251	        }
252	
253	        for (const block of blocks) {
254	            processBlock(block);
255	        }
256	
257	        return lines.join('\n');
258	    }
