263	    updateBlockContent(blocks: OutlineBlock[], blockId: string, newContent: string): OutlineBlock[] {
264	        function updateInBlocks(blockList: OutlineBlock[]): OutlineBlock[] {
265	            return blockList.map(block => {
266	                if (block.id === blockId) {
267	                    return { ...block, content: newContent };
268	                }
269	                return {
270	                    ...block,
271	                    children: updateInBlocks(block.children)
272	                };
273	            });
274	        }
275	        
276	        return updateInBlocks(blocks);
277	    }
