280	     * 插入新块
281	     */
282	    insertBlock(blocks: OutlineBlock[], newBlock: OutlineBlock, afterBlockId?: string): OutlineBlock[] {
283	        if (!afterBlockId) {
284	            return [...blocks, newBlock];
285	        }
286	        
287	        function insertInBlocks(blockList: OutlineBlock[]): OutlineBlock[] {
288	            const result: OutlineBlock[] = [];
289	            
290	            for (const block of blockList) {
291	                result.push({
292	                    ...block,
293	                    children: insertInBlocks(block.children)
294	                });
295	                
296	                if (block.id === afterBlockId) {
297	                    result.push(newBlock);
298	                }
299	            }
300	            
301	            return result;
302	        }
303	        
304	        return insertInBlocks(blocks);
305	    }
